## scripts/knowledge_retrieval.js
```javascript
const fs = require('fs');
const path = require('path');

function extractWords(str) {
  return str.toLowerCase()
    .match(/\b[a-z]+\b/g) || []
    .filter(word => word.length > 4);
}

function cleanMarkdown(str) {
  return str
    .replace(/#/g, '')
    .replace(/\*\*/g, '')
    .replace(/[-*]/g, '')
    .replace(/\n/g, ' ');
}

function calculateScore(taskContent, fileContent) {
  const taskWords = new Set(extractWords(taskContent));
  const fileWords = new Set(extractWords(fileContent));

  if (taskWords.size === 0) return 0;

  let matched = 0;
  for (const word of taskWords) {
    if (fileWords.has(word)) matched++;
  }

  return matched / taskWords.size;
}

function extractFileContent(content) {
  let summary = '';
  const summaryMatch = content.match(/Summary:\s*(.*?)(?=\n\n|\n#|\n-|\n\*|$)/s);
  if (summaryMatch) {
    summary = summaryMatch[1].substring(0, 100);
  } else {
    summary = content.substring(0, 100);
  }

  let keyPoints = [];
  const keyPointsMatch = content.match(/Key Points:\s*(.*?)(?=\n\n|\n#|\n-|\n\*|$)/s);
  if (keyPointsMatch) {
    keyPoints = keyPointsMatch[1].split('\n')
      .map(line => line.trim())
      .filter(line => line && !line.startsWith('-') && !line.startsWith('*'));
  }

  let tags = '';
  const tagsMatch = content.match(/Tags:\s*(.*)/);
  if (tagsMatch) {
    tags = tagsMatch[1];
  }

  return { summary, keyPoints, tags };
}

async function retrieveKnowledge(taskContent, { maxChunks = 3, maxCharsPerChunk = 800 } = {}) {
  const knowledgeDir = path.join(__dirname, 'knowledge');

  if (!fs.existsSync(knowledgeDir) || !fs.lstatSync(knowledgeDir).isDirectory()) {
    return [];
  }

  const files = fs.readdirSync(knowledgeDir)
    .filter(file => file.endsWith('.md'));

  if (files.length === 0) {
    return [];
  }

  const chunks = [];

  for (const file of files) {
    const filePath = path.join(knowledgeDir, file);
    const content = fs.readFileSync(filePath, 'utf-8');

    const { summary, keyPoints, tags } = extractFileContent(content);
    const fileContent = `${summary} ${keyPoints.join(' ')} ${tags}`;
    const score = calculateScore(taskContent, fileContent);

    if (score > 0.1) {
      const excerpt = cleanMarkdown(`${summary} ${keyPoints.join(' ')} ${tags}`);
      chunks.push({
        file,
        excerpt: excerpt.substring(0, maxCharsPerChunk),
        relevanceScore: score
      });
    }
  }

  chunks.sort((a, b) => b.relevanceScore - a.relevanceScore);
  return chunks.slice(0, maxChunks);
}

module.exports = { retrieveKnowledge };
```

